import pytest
from datetime import datetime, timezone, timedelta
from <helper_fn> import api_client

def test_schedule_review_non_manager_role_rejected(
    <fixture:employee_session>, <fixture:reviewee_id>
):
    scheduled_at = (datetime.now(timezone.utc) + timedelta(days=14)).isoformat()
    payload = {
        "reviewee_id": <fixture:reviewee_id>,
        "scheduled_at": scheduled_at
    }
    resp = api_client(
        method="POST",
        path="/performance-reviews/schedule",
        json=payload,
        session=<fixture:employee_session>
    )
    assert resp.status_code == 403, (
        f"Non-manager must be forbidden, got {resp.status_code}: {resp.text}"
    )
